```
And because of that, the migrations tries to migrate it...
```
Your database needs the following change:

  BEGIN TRANSACTION;

  CREATE TABLE "basemodel" ("id" SERIAL NOT NULL PRIMARY KEY); 

  COMMIT;

```

JSONSchema should support to use of load_from or dump_to (or the equivalent in marshmallow 3)

for example:

class CampaignCompletion(Schema):

    id_ = fields.UUID(load_from='id', dump_to='id') 
    version = fields.Integer()
    timestamp = fields.DateTime()
    campaign_name = fields.String(load_from='campaignName', dump_to='campaignName')


Currently this dumps to

{
    "definitions": {
        "CampaignCompletion": {
            "properties": {
                "campaign_name": {
                    "title": "campaign_name",
                    "type": "string"
                },
                "id_": {
                    "title": "id_",
                    "type": "string",
                    "format": "uuid"
                },
                "timestamp": {
                    "title": "timestamp",
                    "type": "string",
                    "format": "date-time"
                },
                "version": {
                    "title": "version",
                    "type": "number",
                    "format": "integer"
                }
            },
            "type": "object",
            "required": []
        }
    },
    "$ref": "#/definitions/CampaignCompletion"
}


In this case, the correct json schema of our model is the one that represents the serialized object, not the python dictionary/object behind the schema. So

{
    "definitions": {
        "CampaignCompletion": {
            "properties": {
                "campaignName": {
                    "title": "campaignName",
                    "type": "string"
                },
                "id": {
                    "title": "id",
                    "type": "string",
                    "format": "uuid"
                },
                "timestamp": {
                    "title": "timestamp",
                    "type": "string",
                    "format": "date-time"
                },
                "version": {
                    "title": "version",
                    "type": "number",
                    "format": "integer"
                }
            },
            "type": "object",
            "required": []
        }
    },
    "$ref": "#/definitions/CampaignCompletion"
}

